import java.util.Scanner;

public class BufferOverflowExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        char[] buffer = new char[10];

        // Copy user input into buffer without checking length
        userInput.getChars(0, userInput.length(), buffer, 0);

        // This loop will try to print characters from the buffer,
        // but if the user input length exceeds the buffer size,
        // it can lead to a buffer overflow vulnerability.

        System.out.println("Contents of buffer:");
        for (int i = 0; i < buffer.length; i++) {
            System.out.print(buffer[i]);
        }

    }
}

