import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        int bufferSize = 10;

        // Check if user input length exceeds buffer size
        if (userInput.length() > bufferSize) {
            System.out.println("Input exceeds buffer size. Please enter a string with length <= " + bufferSize);
            return;
        }

        char[] buffer = new char[bufferSize];

        // Copy user input into buffer
        userInput.getChars(0, userInput.length(), buffer, 0);

        System.out.println("Contents of buffer:");
        for (int i = 0; i < buffer.length; i++) {
            System.out.print(buffer[i]);
        }

    }
}

